def passable(cell, amber, jade, gateA_open, gateB_open, ignore=None, player=None):
    r,c=cell
    if not (0<=r<ROWS and 0<=c<COLS):
        return False
    if cell in WALLS:
        return False
    if cell==(4,2) and not gateB_open:
        return False
    if cell==(4,4) and not gateA_open:
        return False
    if ignore!='amber' and cell==amber:
        return False
    if ignore!='jade' and cell==jade:
        return False
    if player is not None and cell==player:
        return False
    return True


def gateA(amber):
    return amber==PLATE_A

def conv_dir(dials, name):
    return dials[['alpha','beta','gamma','delta'].index(name)]


def slide_entity(pos, dname, amber, jade, gateA_open, gateB_open, kind):
    dr,dc=DIRS[dname]
    cur=pos
    while cur in ICE:
        nxt=(cur[0]+dr, cur[1]+dc)
        ign=kind
        if passable(nxt, amber, jade, gateA_open, gateB_open, ignore=ign):
            cur=nxt
        else:
            break
