def passable(cell, amber, jade, gateB, player_block=None, ignore=None):
    r,c=cell
    if not (0<=r<ROWS and 0<=c<COLS): return False
    if cell in WALLS: return False
    if cell==(4,2) and not gateB: return False
    if cell==(4,4) and not gateA(amber): return False
    if ignore!='amber' and cell==amber: return False
    if ignore!='jade' and cell==jade: return False
    if player_block is not None and cell==player_block: return False
    return True

