    if op=='move':
        d=cmd[1]; dr,dc=DIRS[d]; nxt=(player[0]+dr,player[1]+dc)
        if not passable(nxt,amber,jade,gateB): return None
        player=slide(nxt,d,amber,jade,gateB,None)
    elif op=='push':
        crate,d=cmd[1],cmd[2]; dr,dc=DIRS[d]
        pos=amber if crate=='amber' else jade
